import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Edge: empty
  it("empty item list → premium 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // Base premiums per item type (with first-insurance surcharge per spec)
  it("single sword, newcomer, no previous contract → 100 base + 10 first + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it.todo("single amulet, newcomer, no previous contract → 60 base + 6 first + 5 fee = 71 G");
  it.todo("single staff, newcomer, no previous contract → 80 base + 8 first + 5 fee = 93 G");
  it.todo("single potion, newcomer, no previous contract → 40 base + 4 first + 5 fee = 49 G");

  // Components — basic
  it.todo("1 rune → 25 G base + 2.5 first → 28 G premium (rounded up) + 5 fee = 33 G");
  it.todo("2 runes → 50 G base premium (no block)");
  it.todo("3 runes → 60 G base premium (block applies)");
  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
  it.todo("7 runes → 175 G base premium (2 standalone + … no block forms from 7)");

  // Alike components clarification
  it.todo("2 runes + 1 moonstone → 75 G base premium (no block — different types)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");

  // Modifier scope on multi-item policies
  it.todo("cursed sword + plain amulet, newcomer → 100 + 60 base = 160, curse adds 50 (on sword's base only) = 210 before further modifiers + fee");

  // Modifier thresholds — premiums
  it.todo("customer with exactly 2 years with MHPCO → loyalty discount applies");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("cursed sword with exactly enchantment 5 → both surcharges apply");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");

  // Rounding in MHPCO's favor — premium
  it.todo("a premium calculation that yields 197.5 G → final premium 198 G (rounded up)");

  // Integration examples
  it.todo("Newcomer with cursed sword (steel, enchantment 3): 0 years, no previous → premium 165 G");
  it.todo("Long-standing customer's second contract: 3 years, second quote, cursed sword enchantment 7 → 160 G");

  // Edge — unknown item type at quote
  it.todo("quote with unknown item type (e.g. broomstick) → throws / non-zero exit; no results written");

  // Claim — basics
  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G (full minus 100 G deductible)");
  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G (no special clause)");

  // Claim — enchantment threshold
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");

  // Claim — dragon material
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full reimbursement, then deductible)");

  // Claim — enchantment vs dragon material
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins, then deductible)");
  it.todo("dragon-material sword, exactly enchantment 8, damage 1000 G → payout 400 G");

  // Deductible per damage event (per damaged item)
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");

  // Multiple items of the same type
  it.todo("two swords policy → insurance sum 2000 G, cap 4000 G");
  it.todo("two swords policy with two sword damage entries → each damage gets its own deductible");
  it.todo("policy covers only one sword but damages contain two sword entries → non-zero exit / error");

  // Cap exhaustion
  it.todo("policy with sword and amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword (premium with modifiers 165 G) → cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes (a block) → insurance sum 1750 G; block discount does not affect insurance sum");
  it.todo("sword insured (cap 2000 G), two successive 1500 G claims → first payout 1400 G remainingCap 600 G, second payout 600 G remainingCap 0 G");

  // Rounding — payout
  it.todo("payout calculation that yields 350.5 G → final payout 350 G (rounded down)");

  // Claim errors
  it.todo("claim references damage entry for item not in policy → non-zero exit / error");
  it.todo("claim references damage entry with unknown item type → non-zero exit / error");
  it.todo("claim contains damage entry with amount -200 → non-zero exit / error");
});

